#include <cstdio>

#include <vector>

#include <algorithm>



int main() {

    int N, X, Y;

    scanf("%d %d %d", &N, &X, &Y);

    std::vector <int> count;

    for (int i = 0; i < N; i++) {

        count.push_back(0);

    }

    for (int i = 1; i < N; i++) {

        for (int j = i + 1; j < N + 1; j++) {

            count[std::min({abs(i - j),

                            abs(X - i) + 1 + abs(j - Y),

                            abs(Y - i) + 1 + abs(j - X)})] += 1;

        }

    }

    for (int i = 1; i < N; i++) {

        printf("%d\n", count[i]);

    }

}

